{
  "query": "mutation { signup(input: { username: \"testuser\", email: \"test@example.com\", password: \"password123\" }) { success message token user { _id username email } } }"
}

{
  "query": "query { login(input: { usernameOrEmail: \"testuser\", password: \"password123\" }) { success message token user { _id username email } } }"
}

{
  "query": "query { getAllEmployees { success message count employees { _id first_name last_name email designation department } } }"
}

{
  "query": "mutation { addEmployee(input: { first_name: \"John\", last_name: \"Doe\", email: \"john.doe@company.com\", gender: \"Male\", designation: \"Developer\", salary: 5000, date_of_joining: \"2024-01-15\", department: \"Engineering\" }) { success message employee { _id first_name last_name email } } }"
}

{
  "query": "query { getEmployeeByEid(eid: \"EMPLOYEE_ID_HERE\") { success message employee { _id first_name last_name email designation department } } }"
}

{
  "query": "mutation { updateEmployee(eid: \"EMPLOYEE_ID_HERE\", input: { designation: \"Senior Developer\", salary: 6000 }) { success message employee { _id designation salary } } }"
}

{
  "query": "query { getEmployeesByDesignationOrDepartment(designation: \"Developer\", department: \"Engineering\") { success message count employees { _id first_name last_name designation department } } }"
}
